-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.sp_Nomina_CalcularAntiguedad
  @SessionID NVARCHAR(80),
  @Cedula NVARCHAR(32),
  @FechaCalculo DATE = NULL
AS
BEGIN
  SET NOCOUNT ON;

  IF @FechaCalculo IS NULL SET @FechaCalculo = CAST(SYSUTCDATETIME() AS DATE);

  DECLARE @CompanyId INT;
  DECLARE @BranchId INT;
  DECLARE @FechaIngreso DATE;
  DECLARE @Dias INT = 0;
  DECLARE @Anios INT = 0;
  DECLARE @Meses INT = 0;
  DECLARE @TotalMeses INT = 0;

  EXEC dbo.sp_Nomina_GetScope @CompanyId OUTPUT, @BranchId OUTPUT;

  SELECT TOP 1 @FechaIngreso = e.HireDate
  FROM [master].Employee e
  WHERE e.CompanyId = @CompanyId
    AND e.EmployeeCode = @Cedula
    AND e.IsDeleted = 0;

  IF @FechaIngreso IS NOT NULL
  BEGIN
    SET @Dias = DATEDIFF(DAY, @FechaIngreso, @FechaCalculo);
    SET @Anios = @Dias / 365;
    SET @Meses = (@Dias % 365) / 30;
    SET @TotalMeses = DATEDIFF(MONTH, @FechaIngreso, @FechaCalculo);
  END

  EXEC dbo.sp_Nomina_SetVariable @SessionID, 'ANTI_ANIOS', @Anios, 'AĂ±os de antigĂĽedad';
  EXEC dbo.sp_Nomina_SetVariable @SessionID, 'ANTI_MESES', @Meses, 'Meses de antigĂĽedad';
  EXEC dbo.sp_Nomina_SetVariable @SessionID, 'ANTI_DIAS', @Dias, 'DĂ­as de antigĂĽedad';
  EXEC dbo.sp_Nomina_SetVariable @SessionID, 'ANTI_TOTAL_MESES', @TotalMeses, 'Total meses de antigĂĽedad';
END

GO
 
 
