-- STORED PROCEDURE: dbo.usp_Acct_Account_List
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_Account_List
    @CompanyId   INT,
    @Search      NVARCHAR(100) = NULL,
    @Tipo        NVARCHAR(1)   = NULL,
    @Grupo       NVARCHAR(20)  = NULL,
    @Page        INT           = 1,
    @Limit       INT           = 50,
    @TotalCount  INT           OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    -- Validar paginacion
    IF @Page < 1 SET @Page = 1;
    IF @Limit < 1 SET @Limit = 50;
    IF @Limit > 500 SET @Limit = 500;

    -- Contar total de registros que cumplen los filtros
    SELECT @TotalCount = COUNT(*)
    FROM   acct.Account
    WHERE  CompanyId = @CompanyId
      AND  IsDeleted = 0
      AND  (@Search IS NULL
            OR AccountCode LIKE '%' + @Search + '%'
            OR AccountName LIKE '%' + @Search + '%')
      AND  (@Tipo IS NULL OR AccountType = @Tipo)
      AND  (@Grupo IS NULL OR AccountCode LIKE @Grupo + '%');

    -- Devolver pagina solicitada
    SELECT AccountId,
           AccountCode,
           AccountName,
           AccountType,
           AccountLevel,
           AllowsPosting,
           IsActive
    FROM   acct.Account
    WHERE  CompanyId = @CompanyId
      AND  IsDeleted = 0
      AND  (@Search IS NULL
            OR AccountCode LIKE '%' + @Search + '%'
            OR AccountName LIKE '%' + @Search + '%')
      AND  (@Tipo IS NULL OR AccountType = @Tipo)
      AND  (@Grupo IS NULL OR AccountCode LIKE @Grupo + '%')
    ORDER BY AccountCode
    OFFSET (@Page - 1) * @Limit ROWS
    FETCH NEXT @Limit ROWS ONLY;
END;

GO
 
 
