CREATE PROCEDURE dbo.usp_Acct_Budget_Insert
    @CompanyId       INT,
    @Name            NVARCHAR(200),
    @FiscalYear      SMALLINT,
    @CostCenterCode  NVARCHAR(20)  = NULL,
    @LinesJson       NVARCHAR(MAX),
    @Resultado       INT           OUTPUT,
    @Mensaje         NVARCHAR(500) OUTPUT
AS
