CREATE PROCEDURE dbo.usp_Acct_Budget_Update
    @CompanyId   INT,
    @BudgetId    INT,
    @Name        NVARCHAR(200),
    @LinesJson   NVARCHAR(MAX),
    @Resultado   INT           OUTPUT,
    @Mensaje     NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    SET @Resultado = 0;
    SET @Mensaje   = N'';

