      AND  IsDeleted = 0
      AND  (@Search IS NULL
            OR CostCenterCode LIKE '%' + @Search + '%'
            OR CostCenterName LIKE '%' + @Search + '%')
    ORDER BY CostCenterCode
    OFFSET (@Page - 1) * @Limit ROWS
    FETCH NEXT @Limit ROWS ONLY;
END;
