CREATE PROCEDURE dbo.usp_Acct_DocumentLink_Upsert
    @CompanyId       INT,
    @BranchId        INT,
    @Module          NVARCHAR(40),
    @DocumentType    NVARCHAR(40),
    @OriginDocument  NVARCHAR(120),
    @JournalEntryId  BIGINT,
    @Resultado       INT           OUTPUT,
    @Mensaje         NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    SET @Resultado = 0;
    SET @Mensaje   = N'';

    IF EXISTS (
        SELECT 1
        FROM acct.DocumentLink
        WHERE CompanyId = @CompanyId
          AND BranchId = @BranchId
          AND ModuleCode = @Module
          AND DocumentType = @DocumentType
          AND DocumentNumber = @OriginDocument
    )
    BEGIN
        SET @Resultado = 0;
        SET @Mensaje   = N'El enlace de documento ya existe.';
        RETURN;
    END;

    BEGIN TRY
        INSERT INTO acct.DocumentLink (
            CompanyId,
            BranchId,
            ModuleCode,
            DocumentType,
            DocumentNumber,
            NativeDocumentId,
            JournalEntryId
        )
        VALUES (
            @CompanyId,
            @BranchId,
            @Module,
            @DocumentType,
            @OriginDocument,
            NULL,
            @JournalEntryId
        );

        SET @Resultado = 1;
        SET @Mensaje   = N'Enlace de documento creado exitosamente.';
    END TRY
    BEGIN CATCH
        SET @Resultado = 0;
        SET @Mensaje   = N'Error al insertar enlace: ' + ERROR_MESSAGE();
    END CATCH;
END;

GO
 
 
