-- STORED PROCEDURE: dbo.usp_Acct_Entry_Void
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_Entry_Void
    @CompanyId   INT,
    @BranchId    INT,
    @AsientoId   BIGINT,
    @Motivo      NVARCHAR(400),
    @Resultado   INT           OUTPUT,
    @Mensaje     NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    SET @Resultado = 0;
    SET @Mensaje   = N'';

    IF NOT EXISTS (
        SELECT 1
        FROM acct.JournalEntry
        WHERE CompanyId = @CompanyId
          AND BranchId = @BranchId
          AND JournalEntryId = @AsientoId
          AND IsDeleted = 0
    )
    BEGIN
        SET @Mensaje = N'Asiento no encontrado';
        RETURN;
    END;

    BEGIN TRY
        UPDATE acct.JournalEntry
        SET Status    = N'VOIDED',
            Concept   = CONCAT(
                ISNULL(Concept, ''),
                CASE WHEN ISNULL(Concept, '') = '' THEN '' ELSE ' | ' END,
                'ANULADO: ',
                @Motivo
            ),
            UpdatedAt = SYSUTCDATETIME()
        WHERE CompanyId = @CompanyId
          AND BranchId = @BranchId
          AND JournalEntryId = @AsientoId
          AND IsDeleted = 0;

        IF @@ROWCOUNT > 0
        BEGIN
            SET @Resultado = 1;
            SET @Mensaje   = N'Asiento anulado';
        END
        ELSE
        BEGIN
            SET @Mensaje = N'Asiento no encontrado';
        END;
    END TRY
    BEGIN CATCH
        SET @Resultado = 0;
        SET @Mensaje   = N'Error al anular asiento: ' + ERROR_MESSAGE();
    END CATCH;
END;

GO
 
 
