CREATE PROCEDURE dbo.usp_Acct_Pos_GetTaxSummary
    @SaleTicketId  INT
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        TaxRate       AS taxRate,
        SUM(NetAmount)   AS baseAmount,
        SUM(TaxAmount)   AS taxAmount,
        SUM(TotalAmount) AS totalAmount
