    SET    IsDeleted = 1,
           IsActive  = 0
    WHERE  RecurringEntryId = @RecurringEntryId;

    SET @Resultado = 1;
    SET @Mensaje   = N'Plantilla recurrente eliminada exitosamente.';
END;
