-- =============================================
-- STORED PROCEDURE: dbo.usp_Acct_RecurringEntry_GetDue
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_RecurringEntry_GetDue
    @CompanyId  INT
AS
BEGIN
    SET NOCOUNT ON;

    SELECT RecurringEntryId,
           TemplateName,
           Frequency,
           NextExecutionDate,
           LastExecutedDate,
           TimesExecuted,
           MaxExecutions,
           TipoAsiento,
           Concepto
    FROM   acct.RecurringEntry
    WHERE  CompanyId          = @CompanyId
      AND  IsActive           = 1
      AND  IsDeleted          = 0
      AND  NextExecutionDate <= CAST(SYSUTCDATETIME() AS DATE)
      AND  (MaxExecutions IS NULL OR TimesExecuted < MaxExecutions)
    ORDER BY NextExecutionDate;
END;
GO
 
 
