-- =============================================
-- STORED PROCEDURE: dbo.usp_Acct_RecurringEntry_Insert
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_RecurringEntry_Insert
    @CompanyId          INT,
    @TemplateName       NVARCHAR(200),
    @Frequency          NVARCHAR(10),
    @NextExecutionDate  DATE,
    @TipoAsiento        NVARCHAR(20),
    @Concepto           NVARCHAR(300),
    @MaxExecutions      INT            = NULL,
    @LinesJson          NVARCHAR(MAX),
    @Resultado          INT            OUTPUT,
    @Mensaje            NVARCHAR(500)  OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    SET @Resultado = 0;
    SET @Mensaje   = N'';

    IF @TemplateName IS NULL OR LEN(LTRIM(@TemplateName)) = 0
    BEGIN
        SET @Mensaje = N'El nombre de la plantilla es obligatorio.';
        RETURN;
    END;

    -- Validar que debito = credito en las lineas
    DECLARE @SumDebit  DECIMAL(18,2);
    DECLARE @SumCredit DECIMAL(18,2);

    DECLARE @XmlCheck XML;
    SET @XmlCheck = CAST(@LinesJson AS XML);
    SELECT @SumDebit  = SUM(ISNULL(x.r.value('(debit)[1]', 'DECIMAL(18,2)'), 0)),
           @SumCredit = SUM(ISNULL(x.r.value('(credit)[1]', 'DECIMAL(18,2)'), 0))
    FROM @XmlCheck.nodes('/lines/line') x(r);

    IF ABS(ISNULL(@SumDebit, 0) - ISNULL(@SumCredit, 0)) > 0.01
    BEGIN
        SET @Mensaje = N'Las lineas no estan balanceadas (Debe=' + CAST(@SumDebit AS NVARCHAR(20))
                     + N', Haber=' + CAST(@SumCredit AS NVARCHAR(20)) + N').';
        RETURN;
    END;

    BEGIN TRY
        BEGIN TRAN;

        INSERT INTO acct.RecurringEntry (
            CompanyId, TemplateName, Frequency, NextExecutionDate,
            MaxExecutions, TipoAsiento, Concepto
        )
        VALUES (
            @CompanyId, @TemplateName, @Frequency, @NextExecutionDate,
            @MaxExecutions, @TipoAsiento, @Concepto
        );

        DECLARE @ReId INT;

        SET @ReId = SCOPE_IDENTITY();
        DECLARE @XmlLines3 XML;
        SET @XmlLines3 = CAST(@LinesJson AS XML);

        INSERT INTO acct.RecurringEntryLine (
            RecurringEntryId, AccountCode, Description, CostCenterCode, Debit, Credit
        )
        SELECT @ReId,
               x.r.value('(accountCode)[1]', 'NVARCHAR(20)'),
               x.r.value('(description)[1]', 'NVARCHAR(200)'),
               x.r.value('(costCenterCode)[1]', 'NVARCHAR(20)'),
               ISNULL(x.r.value('(debit)[1]', 'DECIMAL(18,2)'), 0),
               ISNULL(x.r.value('(credit)[1]', 'DECIMAL(18,2)'), 0)
        FROM @XmlLines3.nodes('/lines/line') x(r);

        COMMIT TRAN;
        SET @Resultado = 1;
        SET @Mensaje   = N'Plantilla recurrente creada con ID ' + CAST(@ReId AS NVARCHAR(10)) + N'.';
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRAN;
        SET @Resultado = 0;
        SET @Mensaje   = N'Error al crear plantilla recurrente: ' + ERROR_MESSAGE();
    END CATCH;
END;
GO
 
 
