CREATE PROCEDURE dbo.usp_Acct_Report_BalanceComprobacion
    @CompanyId   INT,
    @BranchId    INT,
    @FechaDesde  DATE,
    @FechaHasta  DATE
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        l.AccountCodeSnapshot  AS codCuenta,
        MAX(a.AccountName)     AS cuenta,
        SUM(l.DebitAmount)     AS totalDebe,
        SUM(l.CreditAmount)    AS totalHaber,
        SUM(l.DebitAmount - l.CreditAmount) AS saldo
    FROM acct.JournalEntryLine l
    INNER JOIN acct.JournalEntry je ON je.JournalEntryId = l.JournalEntryId
    LEFT JOIN acct.Account a ON a.AccountId = l.AccountId
    WHERE je.CompanyId = @CompanyId
      AND je.BranchId = @BranchId
      AND je.IsDeleted = 0
      AND je.Status <> 'VOIDED'
      AND je.EntryDate >= @FechaDesde
      AND je.EntryDate <= @FechaHasta
    GROUP BY l.AccountCodeSnapshot
    ORDER BY l.AccountCodeSnapshot;
END;

GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_Acct_Report_BalanceGeneral
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_Report_BalanceGeneral
    @CompanyId   INT,
    @BranchId    INT,
    @FechaCorte  DATE
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        l.AccountCodeSnapshot  AS codCuenta,
        MAX(a.AccountName)     AS cuenta,
        MAX(a.AccountType)     AS tipo,
        SUM(l.DebitAmount)     AS totalDebe,
        SUM(l.CreditAmount)    AS totalHaber,
        CASE
            WHEN MAX(a.AccountType) = 'A' THEN SUM(l.DebitAmount - l.CreditAmount)
            WHEN MAX(a.AccountType) IN ('P','C') THEN SUM(l.CreditAmount - l.DebitAmount)
            ELSE 0
        END AS saldo
    FROM acct.JournalEntryLine l
    INNER JOIN acct.JournalEntry je ON je.JournalEntryId = l.JournalEntryId
    INNER JOIN acct.Account a ON a.AccountId = l.AccountId
    WHERE je.CompanyId = @CompanyId
      AND je.BranchId = @BranchId
      AND je.IsDeleted = 0
      AND je.Status <> 'VOIDED'
      AND a.AccountType IN ('A', 'P', 'C')
      AND je.EntryDate <= @FechaCorte
    GROUP BY l.AccountCodeSnapshot
    ORDER BY l.AccountCodeSnapshot;
END;

GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_Acct_Report_BalanceReexpresado
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_Report_BalanceReexpresado
    @CompanyId  INT,
    @BranchId   INT,
    @FechaCorte DATE
AS
BEGIN
    SET NOCOUNT ON;

    -- Obtener ajuste mas reciente para el periodo
    DECLARE @PeriodCode CHAR(6) = FORMAT(@FechaCorte, 'yyyyMM');
    DECLARE @Factor DECIMAL(18,8) = 1.0;

    SELECT TOP 1 @Factor = ReexpressionFactor
    FROM   acct.InflationAdjustment
    WHERE  CompanyId = @CompanyId AND BranchId = @BranchId
      AND  PeriodCode <= @PeriodCode AND Status = 'POSTED'
    ORDER BY PeriodCode DESC;

    SELECT a.AccountCode,
           a.AccountName,
           a.AccountType,
           a.AccountLevel,
           -- Saldo historico
           ISNULL(SUM(
               CASE WHEN a.AccountType IN ('A','G')
                    THEN ISNULL(jl.DebitAmount, 0) - ISNULL(jl.CreditAmount, 0)
                    ELSE ISNULL(jl.CreditAmount, 0) - ISNULL(jl.DebitAmount, 0)
               END
           ), 0) AS historicalBalance,
           -- Clasificacion
           ISNULL(mc.Classification, 'MONETARY') AS classification,
           -- Saldo reexpresado
           CASE WHEN ISNULL(mc.Classification, 'MONETARY') = 'NON_MONETARY'
                THEN ROUND(ISNULL(SUM(
                     CASE WHEN a.AccountType IN ('A','G')
                          THEN ISNULL(jl.DebitAmount, 0) - ISNULL(jl.CreditAmount, 0)
                          ELSE ISNULL(jl.CreditAmount, 0) - ISNULL(jl.DebitAmount, 0)
                     END
                ), 0) * @Factor, 2)
                ELSE ISNULL(SUM(
                     CASE WHEN a.AccountType IN ('A','G')
                          THEN ISNULL(jl.DebitAmount, 0) - ISNULL(jl.CreditAmount, 0)
                          ELSE ISNULL(jl.CreditAmount, 0) - ISNULL(jl.DebitAmount, 0)
                     END
                ), 0)
           END AS adjustedBalance,
           -- Monto del ajuste
           CASE WHEN ISNULL(mc.Classification, 'MONETARY') = 'NON_MONETARY'
                THEN ROUND(ISNULL(SUM(
                     CASE WHEN a.AccountType IN ('A','G')
                          THEN ISNULL(jl.DebitAmount, 0) - ISNULL(jl.CreditAmount, 0)
                          ELSE ISNULL(jl.CreditAmount, 0) - ISNULL(jl.DebitAmount, 0)
                     END
                ), 0) * (@Factor - 1.0), 2)
                ELSE 0
           END AS adjustmentAmount
    FROM   acct.Account a
    LEFT JOIN acct.JournalEntryLine jl ON jl.AccountId = a.AccountId
    LEFT JOIN acct.JournalEntry je ON je.JournalEntryId = jl.JournalEntryId
                                  AND je.CompanyId = @CompanyId
                                  AND je.Status = 'APPROVED'
                                  AND je.EntryDate <= @FechaCorte
    LEFT JOIN acct.AccountMonetaryClass mc ON mc.AccountId = a.AccountId AND mc.CompanyId = a.CompanyId
    WHERE  a.CompanyId = @CompanyId
      AND  a.IsActive  = 1
      AND  ISNULL(a.IsDeleted, 0) = 0
      AND  a.AccountType IN ('A','P','C')
    GROUP BY a.AccountCode, a.AccountName, a.AccountType, a.AccountLevel, mc.Classification
    HAVING ISNULL(SUM(
        CASE WHEN a.AccountType IN ('A','G')
             THEN ISNULL(jl.DebitAmount, 0) - ISNULL(jl.CreditAmount, 0)
             ELSE ISNULL(jl.CreditAmount, 0) - ISNULL(jl.DebitAmount, 0)
        END
    ), 0) <> 0
    ORDER BY a.AccountCode;
END;

GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_Acct_Report_CashFlow
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_Report_CashFlow
    @CompanyId   INT,
    @FechaDesde  DATE,
    @FechaHasta  DATE
AS
BEGIN
    SET NOCOUNT ON;

    SELECT CASE
               WHEN a.AccountType IN ('I', 'G') THEN N'OPERACION'
               WHEN a.AccountType = 'A' AND a.AccountLevel >= 3
                    AND a.AccountCode LIKE '1.2%' THEN N'INVERSION'
               WHEN a.AccountType = 'P' AND a.AccountCode LIKE '2.2%' THEN N'FINANCIAMIENTO'
               WHEN a.AccountType = 'C' THEN N'FINANCIAMIENTO'
               ELSE N'OPERACION'
           END AS Category,
           a.AccountCode,
           a.AccountName,
           SUM(jel.DebitAmount - jel.CreditAmount) AS Amount
    FROM   acct.JournalEntryLine jel
    JOIN   acct.JournalEntry je ON je.JournalEntryId = jel.JournalEntryId
    JOIN   acct.Account a       ON a.AccountId       = jel.AccountId
    WHERE  je.CompanyId  = @CompanyId
      AND  je.EntryDate  >= @FechaDesde
      AND  je.EntryDate  <= @FechaHasta
      AND  je.Status     = 'APPROVED'
      AND  je.IsDeleted  = 0
      AND  a.IsDeleted   = 0
    GROUP BY CASE
                 WHEN a.AccountType IN ('I', 'G') THEN N'OPERACION'
                 WHEN a.AccountType = 'A' AND a.AccountLevel >= 3
                      AND a.AccountCode LIKE '1.2%' THEN N'INVERSION'
                 WHEN a.AccountType = 'P' AND a.AccountCode LIKE '2.2%' THEN N'FINANCIAMIENTO'
                 WHEN a.AccountType = 'C' THEN N'FINANCIAMIENTO'
                 ELSE N'OPERACION'
             END,
             a.AccountCode, a.AccountName
    HAVING SUM(jel.DebitAmount - jel.CreditAmount) <> 0
    ORDER BY Category, a.AccountCode;
END;
GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_Acct_Report_DrillDown
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_Report_DrillDown
    @CompanyId    INT,
    @AccountCode  NVARCHAR(20),
    @FechaDesde   DATE,
    @FechaHasta   DATE,
    @Page         INT           = 1,
    @Limit        INT           = 50,
    @TotalCount   INT           OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    IF @Page  < 1   SET @Page  = 1;
    IF @Limit < 1   SET @Limit = 50;
    IF @Limit > 500 SET @Limit = 500;

    -- Obtener AccountId
    DECLARE @AccountId BIGINT;
    SELECT TOP 1 @AccountId = AccountId
    FROM   acct.Account
    WHERE  CompanyId = @CompanyId AND AccountCode = @AccountCode AND IsDeleted = 0;

    IF @AccountId IS NULL
    BEGIN
        SET @TotalCount = 0;
        RETURN;
    END;

    -- Contar total
    SELECT @TotalCount = COUNT(*)
    FROM   acct.JournalEntryLine jel
    JOIN   acct.JournalEntry je ON je.JournalEntryId = jel.JournalEntryId
    WHERE  jel.AccountId = @AccountId
      AND  je.CompanyId  = @CompanyId
      AND  je.EntryDate  >= @FechaDesde
      AND  je.EntryDate  <= @FechaHasta
      AND  je.Status     = 'APPROVED'
      AND  je.IsDeleted  = 0;

    -- Saldo anterior al rango
    DECLARE @SaldoAnterior DECIMAL(18,2);
    SET @SaldoAnterior = 0;
    SELECT @SaldoAnterior = ISNULL(SUM(jel.DebitAmount - jel.CreditAmount), 0)
    FROM   acct.JournalEntryLine jel
    JOIN   acct.JournalEntry je ON je.JournalEntryId = jel.JournalEntryId
    WHERE  jel.AccountId = @AccountId
      AND  je.CompanyId  = @CompanyId
      AND  je.EntryDate  < @FechaDesde
      AND  je.Status     = 'APPROVED'
      AND  je.IsDeleted  = 0;

    -- Detalle con running balance
    SELECT je.JournalEntryId AS EntryId,
           je.EntryDate,
           je.EntryNumber,
           je.EntryType,
           je.Concept,
           je.Status,
           jel.Description AS LineDescription,
           jel.DebitAmount  AS Debit,
           jel.CreditAmount AS Credit,
           jel.CostCenterCode,
           @SaldoAnterior + SUM(jel.DebitAmount - jel.CreditAmount)
               OVER (ORDER BY je.EntryDate, je.JournalEntryId, jel.LineNumber
                     ROWS UNBOUNDED PRECEDING) AS RunningBalance
    FROM   acct.JournalEntryLine jel
    JOIN   acct.JournalEntry je ON je.JournalEntryId = jel.JournalEntryId
    WHERE  jel.AccountId = @AccountId
      AND  je.CompanyId  = @CompanyId
      AND  je.EntryDate  >= @FechaDesde
      AND  je.EntryDate  <= @FechaHasta
      AND  je.Status     = 'APPROVED'
      AND  je.IsDeleted  = 0
    ORDER BY je.EntryDate, je.JournalEntryId, jel.LineNumber
    OFFSET (@Page - 1) * @Limit ROWS
    FETCH NEXT @Limit ROWS ONLY;
END;
GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_Acct_Report_EquityChanges
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_Report_EquityChanges
    @CompanyId  INT,
    @BranchId   INT,
    @FiscalYear SMALLINT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @FechaInicioAnio DATE = DATEFROMPARTS(@FiscalYear, 1, 1);
    DECLARE @FechaFinAnio    DATE = DATEFROMPARTS(@FiscalYear, 12, 31);

    -- Recordset 1: Matriz de cambios por cuenta patrimonial
    SELECT a.AccountCode,
           a.AccountName,
           -- Saldo inicial (movimientos de apertura o saldo acumulado previo)
           ISNULL((
               SELECT SUM(em.Amount)
               FROM   acct.EquityMovement em
               WHERE  em.CompanyId = @CompanyId AND em.BranchId = @BranchId
                 AND  em.AccountCode = a.AccountCode
                 AND  em.FiscalYear = @FiscalYear
                 AND  em.MovementType = 'OPENING_BALANCE'
           ), 0) AS saldoInicial,
           -- Capital
           ISNULL((
               SELECT SUM(em.Amount)
               FROM   acct.EquityMovement em
               WHERE  em.CompanyId = @CompanyId AND em.BranchId = @BranchId
                 AND  em.AccountCode = a.AccountCode
                 AND  em.FiscalYear = @FiscalYear
                 AND  em.MovementType IN ('CAPITAL_INCREASE','CAPITAL_DECREASE')
           ), 0) AS capital,
           -- Reservas
           ISNULL((
               SELECT SUM(em.Amount)
               FROM   acct.EquityMovement em
               WHERE  em.CompanyId = @CompanyId AND em.BranchId = @BranchId
                 AND  em.AccountCode = a.AccountCode
                 AND  em.FiscalYear = @FiscalYear
                 AND  em.MovementType IN ('RESERVE_LEGAL','RESERVE_STATUTORY','RESERVE_VOLUNTARY')
           ), 0) AS reservas,
           -- Resultados
           ISNULL((
               SELECT SUM(em.Amount)
               FROM   acct.EquityMovement em
               WHERE  em.CompanyId = @CompanyId AND em.BranchId = @BranchId
                 AND  em.AccountCode = a.AccountCode
                 AND  em.FiscalYear = @FiscalYear
                 AND  em.MovementType IN ('NET_INCOME','NET_LOSS','RETAINED_EARNINGS','ACCUMULATED_DEFICIT')
           ), 0) AS resultados,
           -- Dividendos
           ISNULL((
               SELECT SUM(em.Amount)
               FROM   acct.EquityMovement em
               WHERE  em.CompanyId = @CompanyId AND em.BranchId = @BranchId
                 AND  em.AccountCode = a.AccountCode
                 AND  em.FiscalYear = @FiscalYear
                 AND  em.MovementType IN ('DIVIDEND_CASH','DIVIDEND_STOCK')
           ), 0) AS dividendos,
           -- Ajuste inflacion
           ISNULL((
               SELECT SUM(em.Amount)
               FROM   acct.EquityMovement em
               WHERE  em.CompanyId = @CompanyId AND em.BranchId = @BranchId
                 AND  em.AccountCode = a.AccountCode
                 AND  em.FiscalYear = @FiscalYear
                 AND  em.MovementType IN ('INFLATION_ADJUST','REVALUATION_SURPLUS')
           ), 0) AS ajusteInflacion,
           -- Otros
           ISNULL((
               SELECT SUM(em.Amount)
               FROM   acct.EquityMovement em
               WHERE  em.CompanyId = @CompanyId AND em.BranchId = @BranchId
                 AND  em.AccountCode = a.AccountCode
                 AND  em.FiscalYear = @FiscalYear
                 AND  em.MovementType = 'OTHER_COMPREHENSIVE'
           ), 0) AS otrosIntegrales,
           -- Saldo final (suma de todos)
           ISNULL((
               SELECT SUM(em.Amount)
               FROM   acct.EquityMovement em
               WHERE  em.CompanyId = @CompanyId AND em.BranchId = @BranchId
                 AND  em.AccountCode = a.AccountCode
                 AND  em.FiscalYear = @FiscalYear
           ), 0) AS saldoFinal
    FROM   acct.Account a
    WHERE  a.CompanyId   = @CompanyId
      AND  a.AccountType = 'C'  -- Patrimonio
      AND  a.IsActive    = 1

      AND  ISNULL(a.IsDeleted, 0) = 0
      AND  EXISTS (
               SELECT 1 FROM acct.EquityMovement em
               WHERE em.CompanyId = @CompanyId AND em.AccountCode = a.AccountCode AND em.FiscalYear = @FiscalYear
           )
    ORDER BY a.AccountCode;

    -- Recordset 2: Totales
    SELECT ISNULL(SUM(CASE WHEN em.MovementType = 'OPENING_BALANCE' THEN em.Amount ELSE 0 END), 0) AS totalSaldoInicial,
           ISNULL(SUM(CASE WHEN em.MovementType IN ('CAPITAL_INCREASE','CAPITAL_DECREASE') THEN em.Amount ELSE 0 END), 0) AS totalCapital,
           ISNULL(SUM(CASE WHEN em.MovementType IN ('RESERVE_LEGAL','RESERVE_STATUTORY','RESERVE_VOLUNTARY') THEN em.Amount ELSE 0 END), 0) AS totalReservas,
           ISNULL(SUM(CASE WHEN em.MovementType IN ('NET_INCOME','NET_LOSS','RETAINED_EARNINGS','ACCUMULATED_DEFICIT') THEN em.Amount ELSE 0 END), 0) AS totalResultados,
           ISNULL(SUM(CASE WHEN em.MovementType IN ('DIVIDEND_CASH','DIVIDEND_STOCK') THEN em.Amount ELSE 0 END), 0) AS totalDividendos,
           ISNULL(SUM(CASE WHEN em.MovementType IN ('INFLATION_ADJUST','REVALUATION_SURPLUS') THEN em.Amount ELSE 0 END), 0) AS totalAjusteInflacion,
           ISNULL(SUM(CASE WHEN em.MovementType = 'OTHER_COMPREHENSIVE' THEN em.Amount ELSE 0 END), 0) AS totalOtrosIntegrales,
           ISNULL(SUM(em.Amount), 0) AS totalSaldoFinal
    FROM   acct.EquityMovement em
    WHERE  em.CompanyId = @CompanyId AND em.BranchId = @BranchId AND em.FiscalYear = @FiscalYear;
END;

GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_Acct_Report_EstadoResultados
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_Report_EstadoResultados
    @CompanyId   INT,
    @BranchId    INT,
    @FechaDesde  DATE,
    @FechaHasta  DATE
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        l.AccountCodeSnapshot  AS codCuenta,
        MAX(a.AccountName)     AS cuenta,
        MAX(a.AccountType)     AS tipo,
        SUM(l.DebitAmount)     AS totalDebe,
        SUM(l.CreditAmount)    AS totalHaber,
        CASE
            WHEN MAX(a.AccountType) = 'I' THEN SUM(l.CreditAmount - l.DebitAmount)
            WHEN MAX(a.AccountType) = 'G' THEN SUM(l.DebitAmount - l.CreditAmount)
            ELSE 0
        END AS monto
    FROM acct.JournalEntryLine l
    INNER JOIN acct.JournalEntry je ON je.JournalEntryId = l.JournalEntryId
    INNER JOIN acct.Account a ON a.AccountId = l.AccountId
    WHERE je.CompanyId = @CompanyId
      AND je.BranchId = @BranchId
      AND je.IsDeleted = 0
      AND je.Status <> 'VOIDED'
      AND a.AccountType IN ('I', 'G')
      AND je.EntryDate >= @FechaDesde
      AND je.EntryDate <= @FechaHasta
    GROUP BY l.AccountCodeSnapshot
    ORDER BY l.AccountCodeSnapshot;
END;

GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_Acct_Report_FinancialRatios
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Acct_Report_FinancialRatios
    @CompanyId   INT,
    @FechaCorte  DATE
AS
BEGIN
    SET NOCOUNT ON;

    -- Acumular saldos por tipo de cuenta
    DECLARE @ActivoCorriente DECIMAL(18,2);
    SET @ActivoCorriente = 0;
    DECLARE @ActivoNoCorriente DECIMAL(18,2);
    SET @ActivoNoCorriente = 0;
    DECLARE @PasivoCorriente DECIMAL(18,2);
    SET @PasivoCorriente = 0;
    DECLARE @PasivoNoCorriente DECIMAL(18,2);
    SET @PasivoNoCorriente = 0;
    DECLARE @Patrimonio DECIMAL(18,2);
    SET @Patrimonio = 0;
    DECLARE @Ingresos DECIMAL(18,2);
    SET @Ingresos = 0;
    DECLARE @CostoVentas DECIMAL(18,2);
    SET @CostoVentas = 0;
    DECLARE @Gastos DECIMAL(18,2);
    SET @Gastos = 0;
    DECLARE @Inventario DECIMAL(18,2);
    SET @Inventario = 0;

    SELECT
        @ActivoCorriente   = SUM(CASE WHEN a.AccountCode LIKE '1.1%' THEN jel.DebitAmount - jel.CreditAmount ELSE 0 END),
        @ActivoNoCorriente = SUM(CASE WHEN a.AccountCode LIKE '1.2%' THEN jel.DebitAmount - jel.CreditAmount ELSE 0 END),
        @PasivoCorriente   = SUM(CASE WHEN a.AccountCode LIKE '2.1%' THEN jel.CreditAmount - jel.DebitAmount ELSE 0 END),
        @PasivoNoCorriente = SUM(CASE WHEN a.AccountCode LIKE '2.2%' THEN jel.CreditAmount - jel.DebitAmount ELSE 0 END),
        @Patrimonio        = SUM(CASE WHEN a.AccountType = 'C'       THEN jel.CreditAmount - jel.DebitAmount ELSE 0 END),
        @Ingresos          = SUM(CASE WHEN a.AccountType = 'I'       THEN jel.CreditAmount - jel.DebitAmount ELSE 0 END),
        @CostoVentas       = SUM(CASE WHEN a.AccountCode LIKE '5.1%' THEN jel.DebitAmount - jel.CreditAmount ELSE 0 END),
        @Gastos            = SUM(CASE WHEN a.AccountType = 'G'       THEN jel.DebitAmount - jel.CreditAmount ELSE 0 END),
        @Inventario        = SUM(CASE WHEN a.AccountCode LIKE '1.1.3%' THEN jel.DebitAmount - jel.CreditAmount ELSE 0 END)
    FROM   acct.JournalEntryLine jel
    JOIN   acct.JournalEntry je ON je.JournalEntryId = jel.JournalEntryId
    JOIN   acct.Account a       ON a.AccountId       = jel.AccountId
    WHERE  je.CompanyId  = @CompanyId
      AND  je.EntryDate  <= @FechaCorte
      AND  je.Status     = 'APPROVED'
      AND  je.IsDeleted  = 0
      AND  a.IsDeleted   = 0;

    DECLARE @TotalPasivo DECIMAL(18,2);

    SET @TotalPasivo = ISNULL(@PasivoCorriente, 0) + ISNULL(@PasivoNoCorriente, 0);
    DECLARE @UtilidadBruta DECIMAL(18,2);
    SET @UtilidadBruta = ISNULL(@Ingresos, 0) - ISNULL(@CostoVentas, 0);
    DECLARE @UtilidadNeta DECIMAL(18,2);
    SET @UtilidadNeta = ISNULL(@Ingresos, 0) - ISNULL(@Gastos, 0);

    SELECT N'CurrentRatio' AS RatioName,
           CASE WHEN ISNULL(@PasivoCorriente, 0) = 0 THEN 0
                ELSE ROUND(ISNULL(@ActivoCorriente, 0) / @PasivoCorriente, 4)
           END AS RatioValue,
           N'LIQUIDEZ' AS Category
    UNION ALL
    SELECT N'QuickRatio',
           CASE WHEN ISNULL(@PasivoCorriente, 0) = 0 THEN 0
                ELSE ROUND((ISNULL(@ActivoCorriente, 0) - ISNULL(@Inventario, 0)) / @PasivoCorriente, 4)
           END,
           N'LIQUIDEZ'
    UNION ALL
    SELECT N'DebtToEquity',
           CASE WHEN ISNULL(@Patrimonio, 0) = 0 THEN 0
                ELSE ROUND(@TotalPasivo / @Patrimonio, 4)
           END,
           N'APALANCAMIENTO'
    UNION ALL
    SELECT N'GrossMargin',
           CASE WHEN ISNULL(@Ingresos, 0) = 0 THEN 0
                ELSE ROUND(@UtilidadBruta / @Ingresos * 100, 2)
           END,
           N'RENTABILIDAD'
    UNION ALL
    SELECT N'NetMargin',
           CASE WHEN ISNULL(@Ingresos, 0) = 0 THEN 0
                ELSE ROUND(@UtilidadNeta / @Ingresos * 100, 2)
           END,
           N'RENTABILIDAD'
    UNION ALL
    SELECT N'WorkingCapital',
           ISNULL(@ActivoCorriente, 0) - ISNULL(@PasivoCorriente, 0),
           N'LIQUIDEZ';
END;
GO
 
 
