CREATE PROCEDURE dbo.usp_Acct_Rest_GetTaxSummary
    @OrderTicketId  INT
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        TaxRate       AS taxRate,
        SUM(NetAmount)   AS baseAmount,
        SUM(TaxAmount)   AS taxAmount,
        SUM(TotalAmount) AS totalAmount
    FROM rest.OrderTicketLine
    WHERE OrderTicketId = @OrderTicketId
    GROUP BY TaxRate;
END;

