CREATE PROCEDURE dbo.usp_AP_Payable_Void
    @Id          BIGINT,
    @Resultado   INT             OUTPUT,
    @Mensaje     NVARCHAR(500)   OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    UPDATE ap.PayableDocument
    SET PendingAmount = 0,
        PaidFlag      = 1,
        Status        = 'VOIDED',
        UpdatedAt     = SYSUTCDATETIME()
    WHERE PayableDocumentId = @Id;

    SET @Resultado = 1;
    SET @Mensaje = N'ok';
END;

