CREATE PROCEDURE dbo.usp_Audit_Log_Insert
    @CompanyId    INT,
    @BranchId     INT,
    @UserId       INT            = NULL,
    @UserName     NVARCHAR(100)  = NULL,
    @ModuleName   NVARCHAR(50),
    @EntityName   NVARCHAR(100),
