    @Summary      NVARCHAR(500)  = NULL,
    @OldValues    NVARCHAR(MAX)  = NULL,
    @NewValues    NVARCHAR(MAX)  = NULL,
    @IpAddress    NVARCHAR(50)   = NULL
AS
BEGIN
