-- =============================================
-- STORED PROCEDURE: dbo.usp_Cfg_AppSetting_Upsert
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Cfg_AppSetting_Upsert
    @CompanyId     INT,
    @Module        NVARCHAR(60),
    @SettingKey    NVARCHAR(128),
    @SettingValue  NVARCHAR(MAX),
    @ValueType     NVARCHAR(30)  = NULL,
    @Description   NVARCHAR(500) = NULL,
    @UserId        INT           = NULL,
    @Resultado     INT           OUTPUT,
    @Mensaje       NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        IF EXISTS (
            SELECT 1
            FROM   cfg.AppSetting
            WHERE  CompanyId  = @CompanyId
              AND  Module     = @Module
              AND  SettingKey = @SettingKey
        )
        BEGIN
            -- Actualizar registro existente
            UPDATE cfg.AppSetting
            SET    SettingValue     = @SettingValue,
                   ValueType       = ISNULL(@ValueType, ValueType),
                   Description     = ISNULL(@Description, Description),
                   UpdatedAt       = GETDATE(),
                   UpdatedByUserId = @UserId
            WHERE  CompanyId  = @CompanyId
              AND  Module     = @Module
              AND  SettingKey = @SettingKey;

            SET @Resultado = 0;
            SET @Mensaje   = N'Configuracion actualizada correctamente.';
        END
        ELSE
        BEGIN
            -- Insertar nuevo registro
            INSERT INTO cfg.AppSetting
                (CompanyId, Module, SettingKey, SettingValue, ValueType, Description,
                 UpdatedAt, UpdatedByUserId)
            VALUES
                (@CompanyId, @Module, @SettingKey, @SettingValue, @ValueType, @Description,
                 GETDATE(), @UserId);

            SET @Resultado = 0;
            SET @Mensaje   = N'Configuracion insertada correctamente.';
        END;
    END TRY
    BEGIN CATCH
        SET @Resultado = ERROR_NUMBER();
        SET @Mensaje   = ERROR_MESSAGE();
    END CATCH;
END;

GO
 
 
