            ClassName = COALESCE(NULLIF(@x.value('(/row/@Descripcion)[1]','NVARCHAR(100)'),N''), ClassName),
            UpdatedAt = SYSUTCDATETIME()
        WHERE ClassId = @Codigo;
        SET @Resultado = 1; SET @Mensaje = N'OK';
