CREATE PROCEDURE dbo.usp_CxC_AplicarCobro
    @RequestId       NVARCHAR(100),
    @CodCliente      NVARCHAR(24),
    @Fecha           NVARCHAR(10),
    @MontoTotal      DECIMAL(18,2),
    @CodUsuario      NVARCHAR(40),
