-- =============================================
-- STORED PROCEDURE: dbo.usp_Doc_PurchaseDocument_List
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Doc_PurchaseDocument_List
    @TipoOperacion  NVARCHAR(20)  = 'COMPRA',
    @Search         NVARCHAR(100) = NULL,
    @Codigo         NVARCHAR(60)  = NULL,
    @FromDate       DATE          = NULL,
    @ToDate         DATE          = NULL,
    @Page           INT           = 1,
    @Limit          INT           = 50,
    @TotalCount     INT           OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    -- Validar parametros de paginacion
    IF @Page < 1 SET @Page = 1;
    IF @Limit < 1 SET @Limit = 50;
    IF @Limit > 500 SET @Limit = 500;

    -- Contar total de registros que coinciden con los filtros
    SELECT @TotalCount = COUNT(*)
    FROM doc.PurchaseDocument
    WHERE DocumentType = @TipoOperacion
      AND IsDeleted = 0
      AND (@Search IS NULL OR (
            DocumentNumber LIKE '%' + @Search + '%'
            OR SupplierName LIKE '%' + @Search + '%'
            OR FiscalId LIKE '%' + @Search + '%'
          ))
      AND (@Codigo IS NULL OR SupplierCode = @Codigo)
      AND (@FromDate IS NULL OR IssueDate >= @FromDate)
      AND (@ToDate IS NULL OR IssueDate < DATEADD(DAY, 1, @ToDate));

    -- Obtener pagina de resultados
    SELECT *
    FROM doc.PurchaseDocument
    WHERE DocumentType = @TipoOperacion
      AND IsDeleted = 0
      AND (@Search IS NULL OR (
            DocumentNumber LIKE '%' + @Search + '%'
            OR SupplierName LIKE '%' + @Search + '%'
            OR FiscalId LIKE '%' + @Search + '%'
          ))
      AND (@Codigo IS NULL OR SupplierCode = @Codigo)
      AND (@FromDate IS NULL OR IssueDate >= @FromDate)
      AND (@ToDate IS NULL OR IssueDate < DATEADD(DAY, 1, @ToDate))
    ORDER BY IssueDate DESC, DocumentNumber DESC
    OFFSET (@Page - 1) * @Limit ROWS
    FETCH NEXT @Limit ROWS ONLY;
END;

GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_Doc_PurchaseDocument_ReceiveOrder
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Doc_PurchaseDocument_ReceiveOrder
    @NumDoc      NVARCHAR(60),
    @CodUsuario  NVARCHAR(60) = 'API'
AS
BEGIN
    SET NOCOUNT ON;

    IF NOT EXISTS (
        SELECT 1 FROM doc.PurchaseDocument
        WHERE DocumentNumber = @NumDoc
          AND DocumentType = 'ORDEN'
          AND IsDeleted = 0
    )
    BEGIN
        SELECT
            CAST(0 AS BIT) AS ok,
            @NumDoc AS numDoc,
            'Orden de compra no encontrada: ' + @NumDoc AS mensaje;
        RETURN;
    END;

    IF EXISTS (
        SELECT 1 FROM doc.PurchaseDocument
        WHERE DocumentNumber = @NumDoc
          AND DocumentType = 'ORDEN'
          AND IsDeleted = 0
          AND IsVoided = 1
    )
    BEGIN
        SELECT
            CAST(0 AS BIT) AS ok,
            @NumDoc AS numDoc,
            'La orden esta anulada y no puede marcarse como recibida: ' + @NumDoc AS mensaje;
        RETURN;
    END;

    UPDATE doc.PurchaseDocument
    SET IsReceived = 'S',
        Notes      = CONCAT(ISNULL(Notes, ''), ' | Recibido ', FORMAT(GETDATE(), 'yyyy-MM-dd HH:mm'),
                      ' por ', @CodUsuario),
        UpdatedAt  = SYSUTCDATETIME()
    WHERE DocumentNumber = @NumDoc
      AND DocumentType = 'ORDEN'
      AND IsDeleted = 0;

    SELECT
        CAST(1 AS BIT) AS ok,
        @NumDoc AS numDoc,
        'Orden marcada como recibida exitosamente: ' + @NumDoc AS mensaje;
END;

GO
 
 
