CREATE PROCEDURE usp_Empresa_Get
AS
BEGIN
    SET NOCOUNT ON;
    SELECT TOP 1
        c.LegalName    AS Empresa,
        c.FiscalId     AS RIF,
        cp.NitCode     AS Nit,
        cp.Phone       AS Telefono,
        cp.AddressLine AS Direccion,
        cp.AltFiscalId AS Rifs
    FROM cfg.Company c
