      AND IsActive = 1;

    IF @@ROWCOUNT <= 0
    BEGIN
        SET @Success = 0;
        SET @Message = N'Banco no encontrado';
        RETURN;
    END;

    SET @Success = 1;
    SET @Message = N'Banco eliminado';
END;

