CREATE PROCEDURE dbo.usp_Fiscal_Declaration_List
    @CompanyId       INT,
    @DeclarationType NVARCHAR(30) = NULL,
    @Year            INT          = NULL,
    @Status          NVARCHAR(20) = NULL,
    @Page            INT          = 1,
    @Limit           INT          = 50,
    @TotalCount      INT          OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    -- Validar parametros de paginacion
    IF @Page  < 1   SET @Page  = 1;
    IF @Limit < 1   SET @Limit = 50;
    IF @Limit > 500  SET @Limit = 500;

    -- Contar registros totales
    SELECT @TotalCount = COUNT(*)
    FROM fiscal.TaxDeclaration
    WHERE CompanyId = @CompanyId
      AND (@DeclarationType IS NULL OR DeclarationType = @DeclarationType)
      AND (@Year            IS NULL OR LEFT(PeriodCode, 4) = CAST(@Year AS VARCHAR(4)))
      AND (@Status          IS NULL OR Status = @Status);

    -- Retornar pagina solicitada
    SELECT
        DeclarationId,
        CompanyId,
        BranchId,
        CountryCode,
        DeclarationType,
        PeriodCode,
        PeriodStart,
        PeriodEnd,
        SalesBase,
        SalesTax,
        PurchasesBase,
        PurchasesTax,
        TaxableBase,
        TaxAmount,
        WithholdingsCredit,
        PreviousBalance,
        NetPayable,
        Status,
        SubmittedAt,
        SubmittedFile,
        AuthorityResponse,
        PaidAt,
        PaymentReference,
        JournalEntryId,
        Notes,
        CreatedBy,
        UpdatedBy,
        CreatedAt,
        UpdatedAt
    FROM fiscal.TaxDeclaration
    WHERE CompanyId = @CompanyId
      AND (@DeclarationType IS NULL OR DeclarationType = @DeclarationType)
      AND (@Year            IS NULL OR LEFT(PeriodCode, 4) = CAST(@Year AS VARCHAR(4)))
      AND (@Status          IS NULL OR Status = @Status)
    ORDER BY PeriodCode DESC
    OFFSET (@Page - 1) * @Limit ROWS
    FETCH NEXT @Limit ROWS ONLY;
END;

