    @Severity                   NVARCHAR(15)    = NULL,
    @BodyPartAffected           NVARCHAR(100)   = NULL,
    @DaysLost                   INT             = NULL,
    @Location                   NVARCHAR(200)   = NULL,
    @Description                NVARCHAR(MAX)   = NULL,
    @RootCause                  NVARCHAR(500)   = NULL,
    @CorrectiveAction           NVARCHAR(500)   = NULL,
