        SET
            ReportedDate               = ISNULL(@ReportedDate, ReportedDate),
            Severity                   = ISNULL(@Severity, Severity),
            BodyPartAffected           = ISNULL(@BodyPartAffected, BodyPartAffected),
            DaysLost                   = ISNULL(@DaysLost, DaysLost),
