CREATE PROCEDURE dbo.usp_HR_Payroll_GetEmployeeLines
    @BatchId      INT,
    @EmployeeCode NVARCHAR(24)
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        bl.LineId,
        bl.BatchId,
        bl.EmployeeId,
        bl.EmployeeCode,
        bl.EmployeeName,
        bl.ConceptCode,
        bl.ConceptName,
        bl.ConceptType,
        bl.Quantity,
        bl.Amount,
        bl.Total,
        bl.IsModified,
        bl.Notes,
        bl.UpdatedAt
    FROM hr.PayrollBatchLine bl
    WHERE bl.BatchId = @BatchId
      AND bl.EmployeeCode = @EmployeeCode
    ORDER BY
        CASE bl.ConceptType
            WHEN N'ASIGNACION' THEN 1
            WHEN N'BONO'       THEN 2
            WHEN N'DEDUCCION'  THEN 3
        END,
        bl.ConceptCode;
END;

