CREATE PROCEDURE dbo.usp_HR_Payroll_ListBatches
    @CompanyId    INT,
    @PayrollCode  NVARCHAR(15) = NULL,
    @Status       NVARCHAR(20) = NULL,
    @Offset       INT          = 0,
    @Limit        INT          = 25,
    @TotalCount   INT          OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    SELECT @TotalCount = COUNT(*)
    FROM hr.PayrollBatch
    WHERE CompanyId = @CompanyId
      AND (@PayrollCode IS NULL OR PayrollCode = @PayrollCode)
      AND (@Status IS NULL OR Status = @Status);

    SELECT
        b.BatchId,
        b.CompanyId,
        b.BranchId,
        b.PayrollCode,
        b.FromDate,
        b.ToDate,
        b.Status,
        b.TotalEmployees,
        b.TotalGross,
        b.TotalDeductions,
        b.TotalNet,
        b.CreatedBy,
        b.CreatedAt,
        b.ApprovedBy,
        b.ApprovedAt,
        b.UpdatedAt
    FROM hr.PayrollBatch b
    WHERE b.CompanyId = @CompanyId
      AND (@PayrollCode IS NULL OR b.PayrollCode = @PayrollCode)
      AND (@Status IS NULL OR b.Status = @Status)
    ORDER BY b.CreatedAt DESC
    OFFSET @Offset ROWS FETCH NEXT @Limit ROWS ONLY;
END;

