CREATE PROCEDURE dbo.usp_HR_Payroll_LoadConceptsForRun
    @CompanyId        INT,
    @PayrollCode      NVARCHAR(15),
    @ConceptType      NVARCHAR(15)  = NULL,
    @ConventionCode   NVARCHAR(30)  = NULL,
    @CalculationType  NVARCHAR(30)  = NULL,
    @SoloLegales      BIT           = 0
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        ConceptCode              AS conceptCode,
        ConceptName              AS conceptName,
        ConceptType              AS conceptType,
        DefaultValue             AS defaultValue,
        Formula                  AS formula,
        AccountingAccountCode    AS accountingAccountCode
    FROM hr.PayrollConcept
    WHERE CompanyId   = @CompanyId
      AND PayrollCode = @PayrollCode
      AND IsActive    = 1
      AND AppliesFlag = 1
      AND (@ConceptType IS NULL OR ConceptType = @ConceptType)
      AND (
            (@SoloLegales = 1 AND (
                (@ConventionCode IS NOT NULL AND ConventionCode = @ConventionCode)
                OR
                (@ConventionCode IS NULL AND ConventionCode IS NOT NULL)
            ))
            OR
            (@SoloLegales = 0 AND (
                (@ConventionCode IS NOT NULL AND (ConventionCode = @ConventionCode OR ConventionCode IS NULL))
                OR
                (@ConventionCode IS NULL)
            ))
          )
      AND (@CalculationType IS NULL OR CalculationType = @CalculationType OR CalculationType IS NULL)
    ORDER BY SortOrder, ConceptCode;
END;

GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_HR_Payroll_ProcessBatch
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_HR_Payroll_ProcessBatch
    @BatchId    INT,
    @UserId     INT,
    @Procesados INT           OUTPUT,
    @Errores    INT           OUTPUT,
    @Resultado  INT           OUTPUT,
    @Mensaje    NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    SET @Procesados = 0;
    SET @Errores    = 0;
    SET @Resultado  = 0;
    SET @Mensaje    = N'';

    -- Validar estado
    DECLARE @CompanyId    INT;
    DECLARE @BranchId     INT;
    DECLARE @PayrollCode  NVARCHAR(15);
    DECLARE @FromDate     DATE;
    DECLARE @ToDate       DATE;
    DECLARE @Status       NVARCHAR(20);

    SELECT
        @CompanyId   = CompanyId,
        @BranchId    = BranchId,
        @PayrollCode = PayrollCode,
        @FromDate    = FromDate,
        @ToDate      = ToDate,
        @Status      = Status
    FROM hr.PayrollBatch
    WHERE BatchId = @BatchId;

    IF @Status IS NULL
    BEGIN
        SET @Resultado = -1;
        SET @Mensaje   = N'Lote no encontrado.';
        RETURN;
    END;

    IF @Status <> N'APROBADA'
    BEGIN
        SET @Resultado = -2;
        SET @Mensaje   = N'Solo se pueden procesar lotes en estado APROBADA. Estado actual: ' + @Status;
        RETURN;
    END;

    -- Cursor de empleados en el lote
    DECLARE @EmpCode   NVARCHAR(24);
    DECLARE @EmpName   NVARCHAR(200);
    DECLARE @EmpId     BIGINT;
    DECLARE @EmpGross  DECIMAL(18,2);
    DECLARE @EmpDeduct DECIMAL(18,2);
    DECLARE @EmpNet    DECIMAL(18,2);
    DECLARE @RunRes    INT;
    DECLARE @RunMsg    NVARCHAR(500);
    DECLARE @LinesXml  NVARCHAR(MAX);

    DECLARE emp_cur CURSOR LOCAL FAST_FORWARD FOR
        SELECT
            EmployeeCode,
            MAX(EmployeeName),
            MAX(EmployeeId),
            ISNULL(SUM(CASE WHEN ConceptType IN (N'ASIGNACION', N'BONO') THEN Total ELSE 0 END), 0),
            ISNULL(SUM(CASE WHEN ConceptType = N'DEDUCCION' THEN Total ELSE 0 END), 0),
            ISNULL(SUM(CASE WHEN ConceptType IN (N'ASIGNACION', N'BONO') THEN Total ELSE 0 END), 0)
            - ISNULL(SUM(CASE WHEN ConceptType = N'DEDUCCION' THEN Total ELSE 0 END), 0)
        FROM hr.PayrollBatchLine
        WHERE BatchId = @BatchId
        GROUP BY EmployeeCode;

    BEGIN TRY
        BEGIN TRANSACTION;

        OPEN emp_cur;
        FETCH NEXT FROM emp_cur INTO @EmpCode, @EmpName, @EmpId, @EmpGross, @EmpDeduct, @EmpNet;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            -- Construir XML de lĂ­neas para este empleado (compatible SQL 2012)
            SET @LinesXml = CAST((
                SELECT
                    ConceptCode  AS [code],
                    ConceptName  AS [name],
                    ConceptType  AS [type],
                    Quantity     AS [qty],
                    Amount       AS [amount],
                    Total        AS [total],
                    ISNULL(Notes, N'') AS [description]
                FROM hr.PayrollBatchLine
                WHERE BatchId = @BatchId
                  AND EmployeeCode = @EmpCode
                FOR XML PATH('line'), ROOT('lines'), TYPE
            ) AS NVARCHAR(MAX));

            BEGIN TRY
                EXEC dbo.usp_HR_Payroll_UpsertRun
                    @CompanyId        = @CompanyId,
                    @BranchId         = @BranchId,
                    @PayrollCode      = @PayrollCode,
                    @EmployeeId       = @EmpId,
                    @EmployeeCode     = @EmpCode,
                    @EmployeeName     = @EmpName,
                    @FromDate         = @FromDate,
                    @ToDate           = @ToDate,
                    @TotalAssignments = @EmpGross,
                    @TotalDeductions  = @EmpDeduct,
                    @NetTotal         = @EmpNet,
                    @PayrollTypeName  = NULL,
                    @UserId           = @UserId,
                    @LinesXml         = @LinesXml,

                    @Resultado        = @RunRes OUTPUT,
                    @Mensaje          = @RunMsg OUTPUT;

                IF @RunRes > 0
                    SET @Procesados = @Procesados + 1;
                ELSE
                    SET @Errores = @Errores + 1;
            END TRY
            BEGIN CATCH
                SET @Errores = @Errores + 1;
            END CATCH;

            FETCH NEXT FROM emp_cur INTO @EmpCode, @EmpName, @EmpId, @EmpGross, @EmpDeduct, @EmpNet;
        END;

        CLOSE emp_cur;
        DEALLOCATE emp_cur;

        -- Actualizar estado del batch
        UPDATE hr.PayrollBatch
        SET Status    = N'PROCESADA',
            UpdatedAt = SYSUTCDATETIME()
        WHERE BatchId = @BatchId;

        COMMIT TRANSACTION;

        SET @Resultado = 1;
        SET @Mensaje   = N'Lote procesado: ' + CAST(@Procesados AS NVARCHAR(10)) + N' empleados procesados, '
                       + CAST(@Errores AS NVARCHAR(10)) + N' errores.';
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;

        IF CURSOR_STATUS('local', 'emp_cur') >= 0
        BEGIN
            CLOSE emp_cur;
            DEALLOCATE emp_cur;
        END;

        SET @Resultado = -99;
        SET @Mensaje   = N'Error: ' + ERROR_MESSAGE();
    END CATCH;
END;

GO
 
 
