-- STORED PROCEDURE: dbo.usp_HR_Payroll_SaveDraftLine
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_HR_Payroll_SaveDraftLine
    @LineId       INT,
    @Quantity     DECIMAL(18,4),
    @Amount       DECIMAL(18,4),
    @Notes        NVARCHAR(500) = NULL,
    @UserId       INT,
    @Resultado    INT           OUTPUT,
    @Mensaje      NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    SET @Resultado = 0;
    SET @Mensaje   = N'';

    -- Validar que la lĂ­nea existe y pertenece a un batch en BORRADOR
    DECLARE @BatchId INT;
    SELECT @BatchId = bl.BatchId
    FROM hr.PayrollBatchLine bl
    INNER JOIN hr.PayrollBatch b ON b.BatchId = bl.BatchId
    WHERE bl.LineId = @LineId
      AND b.Status = N'BORRADOR';

    IF @BatchId IS NULL
    BEGIN
        SET @Resultado = -1;
        SET @Mensaje   = N'LĂ­nea no encontrada o el lote no estĂˇ en estado BORRADOR.';
        RETURN;
    END;

    BEGIN TRY
        UPDATE hr.PayrollBatchLine
        SET Quantity   = @Quantity,
            Amount     = @Amount,
            Total      = @Quantity * @Amount,
            IsModified = 1,
            Notes      = @Notes,
            UpdatedAt  = SYSUTCDATETIME()
        WHERE LineId = @LineId;

        -- Recalcular totales del batch
        UPDATE hr.PayrollBatch
        SET TotalGross     = ISNULL((SELECT SUM(Total) FROM hr.PayrollBatchLine WHERE BatchId = @BatchId AND ConceptType IN (N'ASIGNACION', N'BONO')), 0),
            TotalDeductions= ISNULL((SELECT SUM(Total) FROM hr.PayrollBatchLine WHERE BatchId = @BatchId AND ConceptType = N'DEDUCCION'), 0),
            TotalNet       = ISNULL((SELECT SUM(Total) FROM hr.PayrollBatchLine WHERE BatchId = @BatchId AND ConceptType IN (N'ASIGNACION', N'BONO')), 0)
                           - ISNULL((SELECT SUM(Total) FROM hr.PayrollBatchLine WHERE BatchId = @BatchId AND ConceptType = N'DEDUCCION'), 0),
            UpdatedAt      = SYSUTCDATETIME()
        WHERE BatchId = @BatchId;

        SET @Resultado = 1;
        SET @Mensaje   = N'LĂ­nea actualizada correctamente.';
    END TRY
    BEGIN CATCH
        SET @Resultado = -99;
        SET @Mensaje   = N'Error: ' + ERROR_MESSAGE();
    END CATCH;
END;

GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_HR_Payroll_UpsertRun
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_HR_Payroll_UpsertRun
    @CompanyId         INT,
    @BranchId          INT,
    @PayrollCode       NVARCHAR(15),
    @EmployeeId        BIGINT,
    @EmployeeCode      NVARCHAR(24),
    @EmployeeName      NVARCHAR(200),
    @FromDate          DATE,
    @ToDate            DATE,
    @TotalAssignments  DECIMAL(18,2),
    @TotalDeductions   DECIMAL(18,2),
    @NetTotal          DECIMAL(18,2),
    @PayrollTypeName   NVARCHAR(50)  = NULL,
    @UserId            INT           = NULL,
    @LinesXml          NVARCHAR(MAX) = NULL,
    @Resultado         INT           OUTPUT,
    @Mensaje           NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET XACT_ABORT ON;

    DECLARE @RunId BIGINT;

    BEGIN TRY
        BEGIN TRANSACTION;

        -- Buscar run existente
        SELECT TOP 1 @RunId = PayrollRunId
        FROM hr.PayrollRun
        WHERE CompanyId    = @CompanyId
          AND BranchId     = @BranchId
          AND PayrollCode  = @PayrollCode
          AND EmployeeCode = @EmployeeCode
          AND DateFrom     = @FromDate
          AND DateTo       = @ToDate
          AND RunSource    = N'MANUAL'
        ORDER BY PayrollRunId DESC;

        IF @RunId IS NOT NULL
        BEGIN
            UPDATE hr.PayrollRun
            SET ProcessDate      = CAST(SYSUTCDATETIME() AS DATE),
                TotalAssignments = @TotalAssignments,
                TotalDeductions  = @TotalDeductions,
                NetTotal         = @NetTotal,
                PayrollTypeName  = COALESCE(@PayrollTypeName, PayrollTypeName),
                UpdatedAt        = SYSUTCDATETIME(),
                UpdatedByUserId  = @UserId
            WHERE PayrollRunId = @RunId;

            DELETE FROM hr.PayrollRunLine WHERE PayrollRunId = @RunId;
        END
        ELSE
        BEGIN
            INSERT INTO hr.PayrollRun (
                CompanyId, BranchId, PayrollCode, EmployeeId, EmployeeCode,
                EmployeeName, PositionName, ProcessDate, DateFrom, DateTo,
                TotalAssignments, TotalDeductions, NetTotal, PayrollTypeName,
                RunSource, CreatedByUserId, UpdatedByUserId
            )
            VALUES (
                @CompanyId, @BranchId, @PayrollCode, @EmployeeId, @EmployeeCode,
                @EmployeeName, NULL, CAST(SYSUTCDATETIME() AS DATE), @FromDate, @ToDate,
                @TotalAssignments, @TotalDeductions, @NetTotal, @PayrollTypeName,
                N'MANUAL', @UserId, @UserId
            );

            SET @RunId = SCOPE_IDENTITY();
        END;

        -- Insertar lineas desde XML (reemplaza OPENJSON)
        IF @LinesXml IS NOT NULL AND LEN(@LinesXml) > 2
        BEGIN
            DECLARE @lXml XML = CAST(@LinesXml AS XML);

            INSERT INTO hr.PayrollRunLine (
                PayrollRunId, ConceptCode, ConceptName, ConceptType,
                Quantity, Amount, Total, DescriptionText, AccountingAccountCode
            )
            SELECT
                @RunId,
                r.value('@code', 'NVARCHAR(30)'),
                r.value('@name', 'NVARCHAR(200)'),
                r.value('@type', 'NVARCHAR(20)'),
                CAST(r.value('@quantity', 'NVARCHAR(30)') AS DECIMAL(18,4)),
                CAST(r.value('@amount', 'NVARCHAR(30)') AS DECIMAL(18,4)),
                CAST(r.value('@total', 'NVARCHAR(30)') AS DECIMAL(18,2)),
                r.value('@description', 'NVARCHAR(500)'),
                r.value('@account', 'NVARCHAR(30)')
            FROM @lXml.nodes('/root/row') AS T(r);
        END;

        COMMIT TRANSACTION;

        SET @Resultado = 1;
        SET @Mensaje = N'ok';
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
        SET @Resultado = -99;
        SET @Mensaje = N'Error en upsert run: ' + ERROR_MESSAGE();
    END CATCH;
END;

GO
 
 
