SET ANSI_NULLS ON;
GO

CREATE PROCEDURE dbo.usp_HR_Training_Save
    @TrainingRecordId   INT             = NULL,  -- NULL = INSERT
    @CompanyId          INT,
    @CountryCode        CHAR(2),
    @TrainingType       NVARCHAR(25),
    @Title              NVARCHAR(200),
    @Provider           NVARCHAR(200)   = NULL,
    @StartDate          DATE,
    @EndDate            DATE            = NULL,
    @DurationHours      DECIMAL(6,2),
    @EmployeeId         BIGINT          = NULL,
    @EmployeeCode       NVARCHAR(24),
    @EmployeeName       NVARCHAR(200),
    @CertificateNumber  NVARCHAR(100)   = NULL,
    @CertificateUrl     NVARCHAR(500)   = NULL,
    @Result             NVARCHAR(15)    = NULL,
    @IsRegulatory       BIT             = 0,
    @Notes              NVARCHAR(500)   = NULL,
    @Resultado          INT             OUTPUT,
    @Mensaje            NVARCHAR(500)   OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET @Resultado = 0;
    SET @Mensaje   = '';

    IF @TrainingType NOT IN ('SAFETY','REGULATORY','TECHNICAL','APPRENTICESHIP','INDUCTION')
    BEGIN
        SET @Resultado = -1;
        SET @Mensaje   = 'Tipo de capacitacion no valido.';
        RETURN;
    END

    IF @Result IS NOT NULL AND @Result NOT IN ('PASSED','FAILED','IN_PROGRESS','ATTENDED')
    BEGIN
        SET @Resultado = -1;
        SET @Mensaje   = 'Resultado no valido.';
        RETURN;
    END

    IF @DurationHours <= 0
    BEGIN
        SET @Resultado = -1;
        SET @Mensaje   = 'La duracion en horas debe ser mayor a cero.';
        RETURN;
    END

    BEGIN TRY
        IF @TrainingRecordId IS NULL
        BEGIN
            INSERT INTO hr.TrainingRecord (
                CompanyId, CountryCode, TrainingType, Title, Provider,
                StartDate, EndDate, DurationHours,
                EmployeeId, EmployeeCode, EmployeeName,
                CertificateNumber, CertificateUrl, Result,
                IsRegulatory, Notes, CreatedAt, UpdatedAt
            )
            VALUES (
                @CompanyId, @CountryCode, @TrainingType, @Title, @Provider,
                @StartDate, @EndDate, @DurationHours,
                @EmployeeId, @EmployeeCode, @EmployeeName,
                @CertificateNumber, @CertificateUrl, @Result,
                @IsRegulatory, @Notes, SYSUTCDATETIME(), SYSUTCDATETIME()
            );

            SET @Resultado = SCOPE_IDENTITY();
            SET @Mensaje   = 'Registro de capacitacion creado exitosamente.';
        END
        ELSE
        BEGIN
            IF NOT EXISTS (SELECT 1 FROM hr.TrainingRecord
                           WHERE TrainingRecordId = @TrainingRecordId AND CompanyId = @CompanyId)
            BEGIN
                SET @Resultado = -1;
                SET @Mensaje   = 'Registro de capacitacion no encontrado.';
                RETURN;
            END

            UPDATE hr.TrainingRecord
            SET
                CountryCode       = @CountryCode,
                TrainingType      = @TrainingType,
                Title             = @Title,
                Provider          = @Provider,
                StartDate         = @StartDate,
                EndDate           = @EndDate,
                DurationHours     = @DurationHours,
                EmployeeId        = ISNULL(@EmployeeId, EmployeeId),
                EmployeeCode      = @EmployeeCode,
                EmployeeName      = @EmployeeName,
                CertificateNumber = @CertificateNumber,
                CertificateUrl    = @CertificateUrl,
                Result            = @Result,
                IsRegulatory      = @IsRegulatory,
                Notes             = @Notes,
                UpdatedAt         = SYSUTCDATETIME()
            WHERE TrainingRecordId = @TrainingRecordId
              AND CompanyId = @CompanyId;

            SET @Resultado = @TrainingRecordId;
            SET @Mensaje   = 'Registro de capacitacion actualizado exitosamente.';

        END
    END TRY
    BEGIN CATCH
        SET @Resultado = -1;
        SET @Mensaje   = ERROR_MESSAGE();
    END CATCH
END;

GO
 
 
-- =============================================
-- STORED PROCEDURE: dbo.usp_HR_Trust_CalculateQuarter
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO

CREATE PROCEDURE usp_HR_Trust_CalculateQuarter
    @CompanyId      INT,
    @FiscalYear     INT,
    @Quarter        TINYINT,
    @InterestRate   DECIMAL(8,5) = 0,
    @Resultado      INT OUTPUT,
    @Mensaje        NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET @Resultado = 0;
    SET @Mensaje = '';

    IF @Quarter < 1 OR @Quarter > 4
    BEGIN
        SET @Resultado = -1;
        SET @Mensaje = 'El trimestre debe estar entre 1 y 4.';
        RETURN;
    END

    -- Verificar que no exista calculo previo para este trimestre
    IF EXISTS (
        SELECT 1 FROM hr.SocialBenefitsTrust
        WHERE CompanyId = @CompanyId AND FiscalYear = @FiscalYear AND Quarter = @Quarter
    )
    BEGIN
        SET @Resultado = -2;
        SET @Mensaje = 'Ya existe un calculo para el trimestre ' + CAST(@Quarter AS VARCHAR(1)) + ' del ano ' + CAST(@FiscalYear AS VARCHAR(4)) + '.';
        RETURN;
    END

    BEGIN TRY
        BEGIN TRANSACTION;

        -- Para cada empleado activo, calcular deposito trimestral
        -- LOTTT: 15 dias de salario por trimestre
        -- Despues del primer ano: 2 dias adicionales por ano (max 30 extra)
        INSERT INTO hr.SocialBenefitsTrust (
            CompanyId, EmployeeId, EmployeeCode, EmployeeName,
            FiscalYear, Quarter, DailySalary,
            DaysDeposited, BonusDays, DepositAmount,
            InterestRate, InterestAmount, AccumulatedBalance, Status
        )
        SELECT
            @CompanyId,
            e.EmployeeId,
            e.EmployeeCode,
            e.EmployeeName,
            @FiscalYear,
            @Quarter,
            ROUND(ISNULL((
                SELECT TOP 1 prl.Amount
                FROM hr.PayrollRun pr
                INNER JOIN hr.PayrollRunLine prl ON prl.PayrollRunId = pr.PayrollRunId
                WHERE pr.EmployeeId = e.EmployeeId AND prl.ConceptCode = 'SALARIO_BASE'
                ORDER BY pr.CreatedAt DESC
            ), 0) / 30.0, 2) AS DailySalary,
            15 AS DaysDeposited,
            -- Bonus: 2 dias por cada ano despues del primero, max 30
            CASE
                WHEN @Quarter = 4 AND DATEDIFF(YEAR, e.HireDate, CAST(CAST(@FiscalYear AS VARCHAR(4)) + '-12-31' AS DATE)) > 1
                THEN CASE
                    WHEN (DATEDIFF(YEAR, e.HireDate, CAST(CAST(@FiscalYear AS VARCHAR(4)) + '-12-31' AS DATE)) - 1) * 2 > 30
                    THEN 30
                    ELSE (DATEDIFF(YEAR, e.HireDate, CAST(CAST(@FiscalYear AS VARCHAR(4)) + '-12-31' AS DATE)) - 1) * 2
                END
                ELSE 0
            END AS BonusDays,
            -- DepositAmount = DailySalary * (15 + BonusDays)
            ROUND(
                (ISNULL((
                    SELECT TOP 1 prl.Amount
                    FROM hr.PayrollRun pr
                    INNER JOIN hr.PayrollRunLine prl ON prl.PayrollRunId = pr.PayrollRunId
                    WHERE pr.EmployeeId = e.EmployeeId AND prl.ConceptCode = 'SALARIO_BASE'
                    ORDER BY pr.CreatedAt DESC
                ), 0) / 30.0) * (
                    15 +
                    CASE
                        WHEN @Quarter = 4 AND DATEDIFF(YEAR, e.HireDate, CAST(CAST(@FiscalYear AS VARCHAR(4)) + '-12-31' AS DATE)) > 1
                        THEN CASE
                            WHEN (DATEDIFF(YEAR, e.HireDate, CAST(CAST(@FiscalYear AS VARCHAR(4)) + '-12-31' AS DATE)) - 1) * 2 > 30
                            THEN 30
                            ELSE (DATEDIFF(YEAR, e.HireDate, CAST(CAST(@FiscalYear AS VARCHAR(4)) + '-12-31' AS DATE)) - 1) * 2
                        END
                        ELSE 0
                    END
                )
            , 2) AS DepositAmount,
            @InterestRate,
            -- InterestAmount = saldo acumulado anterior * tasa / 4
            ROUND(
                ISNULL((
                    SELECT TOP 1 t.AccumulatedBalance

                    FROM hr.SocialBenefitsTrust t
                    WHERE t.CompanyId = @CompanyId
                      AND t.EmployeeCode = e.EmployeeCode
                      AND (t.FiscalYear < @FiscalYear OR (t.FiscalYear = @FiscalYear AND t.Quarter < @Quarter))
                    ORDER BY t.FiscalYear DESC, t.Quarter DESC
                ), 0) * (@InterestRate / 100.0) / 4.0
            , 2) AS InterestAmount,
            -- AccumulatedBalance = saldo anterior + deposito + interes
            ISNULL((
                SELECT TOP 1 t.AccumulatedBalance
                FROM hr.SocialBenefitsTrust t
                WHERE t.CompanyId = @CompanyId
                  AND t.EmployeeCode = e.EmployeeCode
                  AND (t.FiscalYear < @FiscalYear OR (t.FiscalYear = @FiscalYear AND t.Quarter < @Quarter))
                ORDER BY t.FiscalYear DESC, t.Quarter DESC
            ), 0)
            +
            ROUND(
                (ISNULL((
                    SELECT TOP 1 prl.Amount
                    FROM hr.PayrollRun pr
                    INNER JOIN hr.PayrollRunLine prl ON prl.PayrollRunId = pr.PayrollRunId
                    WHERE pr.EmployeeId = e.EmployeeId AND prl.ConceptCode = 'SALARIO_BASE'
                    ORDER BY pr.CreatedAt DESC
                ), 0) / 30.0) * (
                    15 +
                    CASE
                        WHEN @Quarter = 4 AND DATEDIFF(YEAR, e.HireDate, CAST(CAST(@FiscalYear AS VARCHAR(4)) + '-12-31' AS DATE)) > 1
                        THEN CASE
                            WHEN (DATEDIFF(YEAR, e.HireDate, CAST(CAST(@FiscalYear AS VARCHAR(4)) + '-12-31' AS DATE)) - 1) * 2 > 30
                            THEN 30
                            ELSE (DATEDIFF(YEAR, e.HireDate, CAST(CAST(@FiscalYear AS VARCHAR(4)) + '-12-31' AS DATE)) - 1) * 2
                        END
                        ELSE 0
                    END
                )
            , 2)
            +
            ROUND(
                ISNULL((
                    SELECT TOP 1 t2.AccumulatedBalance
                    FROM hr.SocialBenefitsTrust t2
                    WHERE t2.CompanyId = @CompanyId
                      AND t2.EmployeeCode = e.EmployeeCode
                      AND (t2.FiscalYear < @FiscalYear OR (t2.FiscalYear = @FiscalYear AND t2.Quarter < @Quarter))
                    ORDER BY t2.FiscalYear DESC, t2.Quarter DESC
                ), 0) * (@InterestRate / 100.0) / 4.0
            , 2) AS AccumulatedBalance,
            'PENDIENTE'
        FROM master.Employee e
        WHERE e.CompanyId = @CompanyId
          AND e.IsActive = 1
          AND e.HireDate <= CAST(CAST(@FiscalYear AS VARCHAR(4)) + '-' + RIGHT('0' + CAST(@Quarter * 3 AS VARCHAR(2)), 2) + '-28' AS DATE);

        DECLARE @Inserted INT = @@ROWCOUNT;

        COMMIT TRANSACTION;

        SET @Resultado = @Inserted;
        SET @Mensaje = 'Fideicomiso calculado para ' + CAST(@Inserted AS VARCHAR(10)) + ' empleados.';

    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
        SET @Resultado = -99;
        SET @Mensaje = ERROR_MESSAGE();
    END CATCH
END

GO
 
 
