AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        COUNT(*) AS TotalEmployees,
        SUM(t.DepositAmount) AS TotalDeposits,
        SUM(t.InterestAmount) AS TotalInterest,
        SUM(t.BonusDays) AS TotalBonusDays,
        SUM(t.AccumulatedBalance) AS TotalAccumulatedBalance,
