        t.DailySalary,
        t.DaysDeposited,
        t.BonusDays,
        t.DepositAmount,
        t.InterestRate,
        t.InterestAmount,
        t.AccumulatedBalance,
        t.Status
    FROM hr.SocialBenefitsTrust t
    WHERE t.CompanyId = @CompanyId AND t.FiscalYear = @FiscalYear AND t.Quarter = @Quarter
    ORDER BY t.EmployeeName;
END

