    EXEC sp_xml_preparedocument @hDoc OUTPUT, @RowXml;
    
    DECLARE @Codigo NVARCHAR(50), @Desc NVARCHAR(200), @Cat NVARCHAR(50),
            @Unit NVARCHAR(20), @Price DECIMAL(18,2), @Cost DECIMAL(18,2),
            @Tax DECIMAL(5,2), @Stock DECIMAL(18,2), @IsSvc BIT;
    
    SELECT @Codigo=CODIGO, @Desc=DESCRIPCION, @Cat=Categoria,
           @Unit=Unidad, @Price=VENTA, @Cost=PRECIO_COMPRA,
           @Tax=PORCENTAJE, @Stock=EXISTENCIA, @IsSvc=es_servicio
    FROM OPENXML(@hDoc, '/row', 1) WITH (
        CODIGO NVARCHAR(50), DESCRIPCION NVARCHAR(200), Categoria NVARCHAR(50),
        Unidad NVARCHAR(20), VENTA DECIMAL(18,2), PRECIO_COMPRA DECIMAL(18,2),
        PORCENTAJE DECIMAL(5,2), EXISTENCIA DECIMAL(18,2), es_servicio BIT
    );
    EXEC sp_xml_removedocument @hDoc;
    
    IF EXISTS (SELECT 1 FROM [master].Product WHERE ProductCode=@Codigo AND IsDeleted=0)
    BEGIN
        SET @Resultado = 0;
        SET @Mensaje = 'Ya existe un articulo con ese codigo';
        RETURN;
    END
    
    INSERT INTO [master].Product (CompanyId, ProductCode, ProductName, CategoryCode, UnitCode, SalesPrice, CostPrice, DefaultTaxRate, StockQty, IsService, IsActive, CreatedAt)
    VALUES (1, @Codigo, @Desc, @Cat, @Unit, ISNULL(@Price,0), ISNULL(@Cost,0), ISNULL(@Tax,0), ISNULL(@Stock,0), ISNULL(@IsSvc,0), 1, GETDATE());
    
    SET @Resultado = 1;
    SET @Mensaje = 'Articulo creado exitosamente';
END

GO
 
 
