CREATE PROCEDURE dbo.usp_Inventario_Update
    @Codigo      NVARCHAR(50),
    @RowXml      NVARCHAR(MAX),
    @Resultado   INT OUTPUT,
    @Mensaje     NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @hDoc INT;
    EXEC sp_xml_preparedocument @hDoc OUTPUT, @RowXml;
    
    DECLARE @Desc NVARCHAR(200), @Cat NVARCHAR(50),
            @Unit NVARCHAR(20), @Price DECIMAL(18,2), @Cost DECIMAL(18,2),
            @Tax DECIMAL(5,2), @Stock DECIMAL(18,2), @IsSvc BIT;
    
    SELECT @Desc=DESCRIPCION, @Cat=Categoria,
           @Unit=Unidad, @Price=VENTA, @Cost=PRECIO_COMPRA,
           @Tax=PORCENTAJE, @Stock=EXISTENCIA, @IsSvc=es_servicio
    FROM OPENXML(@hDoc, '/row', 1) WITH (
        DESCRIPCION NVARCHAR(200), Categoria NVARCHAR(50),
        Unidad NVARCHAR(20), VENTA DECIMAL(18,2), PRECIO_COMPRA DECIMAL(18,2),
        PORCENTAJE DECIMAL(5,2), EXISTENCIA DECIMAL(18,2), es_servicio BIT
    );
    EXEC sp_xml_removedocument @hDoc;
    
    IF NOT EXISTS (SELECT 1 FROM [master].Product WHERE ProductCode=@Codigo AND IsDeleted=0)
    BEGIN
        SET @Resultado = 0;
        SET @Mensaje = 'Articulo no encontrado';
        RETURN;
    END
    
    UPDATE [master].Product SET
        ProductName = ISNULL(@Desc, ProductName),
        CategoryCode = ISNULL(@Cat, CategoryCode),
        UnitCode = ISNULL(@Unit, UnitCode),
        SalesPrice = ISNULL(@Price, SalesPrice),
        CostPrice = ISNULL(@Cost, CostPrice),
        DefaultTaxRate = ISNULL(@Tax, DefaultTaxRate),
        StockQty = ISNULL(@Stock, StockQty),
        IsService = ISNULL(@IsSvc, IsService),
        UpdatedAt = GETDATE()
    WHERE ProductCode = @Codigo AND IsDeleted = 0;
    
    SET @Resultado = 1;
    SET @Mensaje = 'Articulo actualizado exitosamente';
END

GO
 
 
