    WHERE IsDeleted = 0 AND (@S IS NULL OR LineName LIKE @S OR CAST(LineId AS NVARCHAR(20)) LIKE @S)
    ORDER BY LineId OFFSET @Offset ROWS FETCH NEXT @Limit ROWS ONLY;
END

