-- =============================================
-- STORED PROCEDURE: dbo.usp_Pay_CardReader_Upsert
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Pay_CardReader_Upsert
    @DeviceId         INT           = NULL,
    @CompanyId        INT,
    @BranchId         INT           = 0,
    @StationId        NVARCHAR(50)  = 'DEFAULT',
    @DeviceName       NVARCHAR(100),
    @DeviceType       NVARCHAR(30),
    @ConnectionType   NVARCHAR(30)  = 'USB',
    @ConnectionConfig NVARCHAR(500) = NULL,
    @ProviderId       INT           = NULL
AS
BEGIN
    SET NOCOUNT ON;

    IF @DeviceId IS NOT NULL
    BEGIN
        -- Actualizar dispositivo existente
        UPDATE pay.CardReaderDevices
        SET    DeviceName       = @DeviceName,
               DeviceType       = @DeviceType,
               ConnectionType   = @ConnectionType,
               ConnectionConfig = COALESCE(@ConnectionConfig, ConnectionConfig),
               ProviderId       = @ProviderId,
               StationId        = @StationId
        WHERE  Id = @DeviceId;
    END
    ELSE
    BEGIN
        -- Insertar nuevo dispositivo
        INSERT INTO pay.CardReaderDevices (
            EmpresaId,
            SucursalId,
            StationId,
            DeviceName,
            DeviceType,
            ConnectionType,
            ConnectionConfig,
            ProviderId,
            IsActive,
            CreatedAt
        )
        VALUES (
            @CompanyId,
            @BranchId,
            @StationId,
            @DeviceName,
            @DeviceType,
            @ConnectionType,
            @ConnectionConfig,
            @ProviderId,
            1,
            GETDATE()
        );
    END;
END;

GO
 
 
