CREATE PROCEDURE dbo.usp_Pay_Method_Upsert
    @MethodCode   NVARCHAR(30),
    @MethodName   NVARCHAR(100),
    @CountryCode  CHAR(2)       = NULL,
    @MethodType   NVARCHAR(30)  = NULL,
    @IsActive     BIT           = 1
AS
