CREATE PROCEDURE dbo.usp_POS_Customer_Search
    @CompanyId INT,
    @Search    NVARCHAR(200) = NULL,
    @Limit     INT = 20
AS
BEGIN
    SET NOCOUNT ON;

    SELECT TOP (@Limit)
        CustomerId   AS id,
        CustomerCode AS codigo,
        CustomerName AS nombre,
        FiscalId     AS rif,
        Phone        AS telefono,
        Email        AS email,
        AddressLine  AS direccion,
        N'Detal'     AS tipoPrecio,
        CreditLimit  AS credito
    FROM [master].Customer
    WHERE CompanyId = @CompanyId
      AND IsDeleted = 0
      AND IsActive  = 1
      AND (
          @Search IS NULL
          OR CustomerCode LIKE @Search
          OR CustomerName LIKE @Search
          OR FiscalId LIKE @Search
      )
    ORDER BY CustomerName;
END;

