CREATE PROCEDURE dbo.usp_POS_LoadCountryTaxRates
    @CountryCode NVARCHAR(5)
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        TaxCode   AS taxCode,
        Rate      AS rate,
