-- STORED PROCEDURE: dbo.usp_Rest_OrderTicket_RecalcTotals
-- =============================================
SET QUOTED_IDENTIFIER ON;
SET ANSI_NULLS ON;
GO
CREATE PROCEDURE dbo.usp_Rest_OrderTicket_RecalcTotals
    @OrderId INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @Net   DECIMAL(18,2);
    DECLARE @Tax   DECIMAL(18,2);
    DECLARE @Total DECIMAL(18,2);

    SELECT
        @Net   = ISNULL(SUM(NetAmount), 0),
        @Tax   = ISNULL(SUM(TaxAmount), 0),
        @Total = ISNULL(SUM(TotalAmount), 0)
    FROM rest.OrderTicketLine
    WHERE OrderTicketId = @OrderId;

    UPDATE rest.OrderTicket
    SET NetAmount   = @Net,
        TaxAmount   = @Tax,
        TotalAmount = @Total,
        UpdatedAt   = SYSUTCDATETIME()
    WHERE OrderTicketId = @OrderId;
END;

GO
 
 
