CREATE PROCEDURE dbo.usp_Sec_User_GetAvatar
    @CodUsuario  NVARCHAR(60)
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        SELECT TOP 1 Avatar
        FROM   dbo.Usuarios
        WHERE  Cod_Usuario = @CodUsuario;
    END TRY
    BEGIN CATCH
        -- La columna Avatar podria no existir en instalaciones antiguas
        SELECT CAST(NULL AS NVARCHAR(MAX)) AS Avatar
        WHERE  1 = 0;
    END CATCH;
END;

