    UPDATE [master].[CustomerAddress]
    SET IsDeleted = 1, IsDefault = 0, UpdatedAt = SYSUTCDATETIME()
    WHERE AddressId = @AddressId AND CustomerCode = @CustomerCode;

    SET @Resultado = 1;
    SET @Mensaje = N'OK';
END;

