CREATE PROCEDURE dbo.usp_Store_IndustryTemplate_List
    @CompanyId INT = 1
AS
BEGIN
    SET NOCOUNT ON;

    -- Recordset 1: Plantillas
    SELECT
        it.IndustryTemplateId AS id,
        it.TemplateCode       AS code,
        it.TemplateName       AS name,
        it.Description        AS description,
