        ita.SortOrder          AS sortOrder
    FROM store.IndustryTemplateAttribute ita
    WHERE ita.CompanyId = @CompanyId
      AND ita.IsDeleted = 0
      AND ita.IsActive  = 1
    ORDER BY ita.TemplateCode, ita.SortOrder;
END;

