CREATE PROCEDURE dbo.usp_Sys_GetTableColumns
    @SchemaName  NVARCHAR(20),
    @TableName   NVARCHAR(128)
AS
BEGIN
    SET NOCOUNT ON;

    SELECT COLUMN_NAME
    FROM   INFORMATION_SCHEMA.COLUMNS
    WHERE  TABLE_SCHEMA = @SchemaName
      AND  TABLE_NAME   = @TableName
    ORDER BY ORDINAL_POSITION;
END;

